CREATE OR REPLACE FUNCTION fpa_com_get_telephone (as_memno char) RETURNS varchar AS $body$
DECLARE

ls_tel sc_mem_m_member_address.telephone%type;

BEGIN
  select  telephone into STRICT ls_tel
  from    sc_mem_m_member_address
  where   membership_no = as_memno
  and     address_type = '0'
;

  if coalesce(ls_tel::text, '') = '' then ls_tel := '';end if;

  return ls_tel;
  exception
  when  no_data_found then return ' ';
  when others then CALL spa_dberror('FPA_COM_GET_TELEPHONE');

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
